import React, { useState, useEffect, useRef } from 'react';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);
  const containerRef = useRef(null);
  const [positions, setPositions] = useState([]);

  const allSkills = [
    { name: 'HTML5', icon: '🌐' },
    { name: 'CSS3', icon: '🎨' },
    { name: 'JavaScript', icon: '⚡' },
    { name: 'TypeScript', icon: '📘' },
    { name: 'React', icon: '⚛️' },
    { name: 'Next.js', icon: '▲' },
    { name: 'Tailwind CSS', icon: '💨' },
    { name: 'Redux', icon: '🔄' },
    { name: 'Framer Motion', icon: '🎬' },
    { name: 'Node.js', icon: '🟢' },
    { name: 'Express.js', icon: '🚀' },
    { name: 'MongoDB', icon: '🍃' },
    { name: 'MySQL', icon: '🐬' },
    { name: 'PostgreSQL', icon: '🐘' },
    { name: 'Firebase', icon: '🔥' },
    { name: 'JWT', icon: '🔐' },
    { name: 'REST API', icon: '🔗' },
    { name: 'Socket.io', icon: '📡' },
    { name: 'Java', icon: '☕' },
    { name: 'Python', icon: '🐍' },
    { name: 'C++', icon: '⚙️' },
    { name: 'C', icon: '🔧' },
    { name: 'C#', icon: '🎯' },
    { name: 'PHP', icon: '🐘' },
    { name: 'Git', icon: '🔀' },
    { name: 'GitHub', icon: '🐙' },
    { name: 'Docker', icon: '🐳' },
    { name: 'Linux', icon: '🐧' },
    { name: 'VS Code', icon: '💻' },
    { name: 'Postman', icon: '📮' },
    { name: 'Figma', icon: '🎯' }
  ];

  // Initialize positions like rain
  useEffect(() => {
    const initialPositions = allSkills.map(() => ({
      x: Math.random() * 90 + 5,
      y: Math.random() * 90 + 5,
      speed: 0.3 + Math.random() * 0.5,
      delay: Math.random() * 5,
      size: 50 + Math.random() * 30,
      rotation: Math.random() * 360,
      wobble: Math.random() * 2,
      wobbleSpeed: 0.5 + Math.random() * 0.5
    }));
    setPositions(initialPositions);
  }, []);

  // Rain animation
  useEffect(() => {
    if (positions.length === 0) return;

    let animationId;
    let startTime = Date.now();

    const animateRain = () => {
      const elapsed = (Date.now() - startTime) / 1000;

      setPositions(prev => 
        prev.map((pos, index) => {
          // Calculate new Y position (falling down)
          let newY = pos.y + pos.speed * 0.3;

          // Reset to top if reaches bottom
          if (newY > 95) {
            newY = -5;
            // Randomize X slightly for natural look
            pos.x = Math.random() * 90 + 5;
          }

          // Wobble effect (side to side)
          const wobbleOffset = Math.sin(elapsed * pos.wobbleSpeed + index) * pos.wobble;

          return {
            ...pos,
            y: newY,
            x: pos.x + wobbleOffset * 0.05,
            rotation: pos.rotation + 0.2
          };
        })
      );

      animationId = requestAnimationFrame(animateRain);
    };

    // Start animation after initial delay
    const timeout = setTimeout(() => {
      animateRain();
    }, 1000);

    return () => {
      clearTimeout(timeout);
      if (animationId) cancelAnimationFrame(animationId);
    };
  }, [positions.length]);

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden min-h-screen">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div 
          ref={containerRef}
          className="relative min-h-[600px] w-full overflow-hidden rounded-3xl"
          style={{
            background: 'radial-gradient(ellipse at center, rgba(139,92,246,0.03) 0%, transparent 70%)'
          }}
        >
          {/* Rain Particles Background */}
          <div className="absolute inset-0 pointer-events-none overflow-hidden">
            {[...Array(15)].map((_, i) => (
              <div
                key={i}
                className="absolute w-0.5 h-8 bg-purple-400/5 rounded-full"
                style={{
                  left: `${Math.random() * 100}%`,
                  top: `${Math.random() * 100}%`,
                  animation: `rainDrop ${8 + Math.random() * 12}s linear infinite`,
                  animationDelay: `${Math.random() * 10}s`,
                  transform: 'rotate(5deg)'
                }}
              />
            ))}
          </div>

          {/* Skills - Falling like Rain */}
          <div className="relative w-full h-full">
            {positions.map((pos, index) => {
              const skill = allSkills[index];
              if (!skill) return null;

              const isHovered = hoveredSkill === skill.name;

              return (
                <div
                  key={skill.name}
                  className="absolute cursor-pointer transition-all duration-300"
                  style={{
                    left: `${pos.x}%`,
                    top: `${pos.y}%`,
                    transform: `translate(-50%, -50%) rotate(${pos.rotation}deg)`,
                    zIndex: isHovered ? 50 : 10,
                    opacity: isHovered ? 1 : 0.7
                  }}
                  onMouseEnter={() => setHoveredSkill(skill.name)}
                  onMouseLeave={() => setHoveredSkill(null)}
                >
                  <div
                    className="flex flex-col items-center justify-center rounded-full transition-all duration-300"
                    style={{
                      width: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                      height: isHovered ? `${pos.size + 30}px` : `${pos.size}px`,
                      boxShadow: isHovered 
                        ? '0 0 60px rgba(139,92,246,0.4), 0 0 120px rgba(139,92,246,0.15)' 
                        : 'none',
                      background: isHovered 
                        ? 'rgba(26,31,46,0.9)' 
                        : 'rgba(26,31,46,0.15)',
                      border: isHovered 
                        ? '1.5px solid rgba(139,92,246,0.5)' 
                        : '1px solid rgba(255,255,255,0.03)',
                      transform: isHovered ? 'scale(1.2)' : 'scale(1)'
                    }}
                  >
                    <span
                      className="transition-all duration-300"
                      style={{
                        fontSize: isHovered ? '30px' : '18px',
                        filter: isHovered 
                          ? 'brightness(1.3) drop-shadow(0 0 20px rgba(139,92,246,0.3))' 
                          : 'brightness(0.7)'
                      }}
                    >
                      {skill.icon}
                    </span>

                    {isHovered && (
                      <span className="text-[9px] font-semibold text-white mt-0.5 animate-fadeIn">
                        {skill.name}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
            <div className="text-[10px] text-gray-500">Happy Clients</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
            <div className="text-[10px] text-gray-500">Years Experience</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">200</div>
            <div className="text-[10px] text-gray-500">Cups of Coffee</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">5</div>
            <div className="text-[10px] text-gray-500">Technologies Mastered</div>
          </div>
        </div>

        <div className="text-center text-gray-500 text-xs mt-4 opacity-60">
          Hover on any skill to see more ✨
        </div>
      </div>

      <style>{`
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: scale(0.8);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }
        .animate-fadeIn {
          animation: fadeIn 0.25s ease-out forwards;
        }

        @keyframes rainDrop {
          0% {
            transform: translateY(-50px) rotate(5deg);
            opacity: 0;
          }
          10% {
            opacity: 1;
          }
          90% {
            opacity: 1;
          }
          100% {
            transform: translateY(calc(100vh)) rotate(5deg);
            opacity: 0;
          }
        }

        .glass-card {
          background: rgba(17, 17, 17, 0.4);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.03);
          transition: all 0.3s ease;
        }

        .glass-card:hover {
          border-color: rgba(139, 92, 246, 0.1);
        }
      `}</style>
    </section>
  );
};

export default Skills;
